        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    logic = filter_logic.upper()
    if logic not in ("AND", "OR"):
        raise ValueError("filter_logic must be 'AND' or 'OR'")

    engine = MetadataFilterEngine(logic=logic)

    # Convert SearchResult objects to dictionaries suitable for filtering
    records = []
    for result in search_results:
        # Prefer a metadata-like attribute if present; fall back to __dict__
        if hasattr(result, "metadata") and isinstance(result.metadata, dict):
            base = dict(result.metadata)
        else:
            base = {
                k: v
                for k, v in vars(result).items()
                if not k.startswith("_")
            }

        # Ensure core attributes are available to the filter engine
        # without overwriting any explicit metadata fields.
        for attr in ("id", "score", "content", "text"):
            if hasattr(result, attr) and attr not in base:
                base[attr] = getattr(result, attr)

        records.append(base)

    # Use MetadataFilterEngine to get a boolean mask or filtered records
    # The typical pattern is that the engine exposes a `match`/`filter` style API.
    # Here we first try `filter`, then fall back to `match` producing a mask.
    if hasattr(engine, "filter"):
        filtered_records = engine.filter(records, filter_specs)
        # `filter` is expected to return a subset of the original `records`
        # in the same order. Map them back to SearchResult by index.
        # Build an index from record identity to position.
        record_index = {id(rec): idx for idx, rec in enumerate(records)}
        kept_indices = []
        for rec in filtered_records:
            idx = record_index.get(id(rec))
            if idx is not None:
                kept_indices.append(idx)
        return [search_results[i] for i in kept_indices]

    elif hasattr(engine, "match"):
        # Assume `match` returns a list of booleans paralleling the input.
        mask = engine.match(records, filter_specs)
        if len(mask) != len(search_results):
            raise RuntimeError("MetadataFilterEngine.match returned mask of unexpected length")
        return [res for res, keep in zip(search_results, mask) if keep]

